from lxml import etree

def process_soap_request(xml_string, dtd_string):
    # Parse the DTD
    dtd = etree.DTD(dtd_string)
    
    # Parse the XML
    parser = etree.XMLParser(dtd_validation=True)
    try:
        root = etree.fromstring(xml_string, parser)
    except etree.XMLSyntaxError as e:
        raise ValueError("Invalid XML or DTD: " + str(e))
    
    # Validate against DTD
    if not dtd.validate(root):
        raise ValueError("XML does not conform to DTD: " + str(dtd.error_log))
    
    # Extract the SOAP body
    namespaces = {'soap': 'http://schemas.xmlsoap.org/soap/envelope/'}
    body = root.find('soap:Body', namespaces)
    if body is None:
        raise ValueError("No SOAP Body found")
    
    return etree.tostring(body, pretty_print=True).decode('utf-8')